Here's how to save and restore draft text using Window lifecycle events:

**1. Create a custom `Window` subclass in `App.xaml.cs`:**

```csharp
public partial class App : Application
{
    protected override Window CreateWindow(IActivationState? activationState)
    {
        return new AppWindow(new AppShell());
    }
}

public class AppWindow : Window
{
    public AppWindow(Page page) : base(page) { }

    protected override void OnStopped()
    {
        base.OnStopped();
        Preferences.Set("draft_text", NoteDraftState.CurrentDraft);
    }

    protected override void OnResumed()
    {
        base.OnResumed();
        NoteDraftState.CurrentDraft = Preferences.Get("draft_text", string.Empty);
        NoteDraftState.OnDraftRestored?.Invoke();
    }

    protected override void OnDestroying()
    {
        base.OnDestroying();
        // Android back-button can skip Stopped entirely
        Preferences.Set("draft_text", NoteDraftState.CurrentDraft);
    }
}

// Simple shared state so the Window and page can communicate
public static class NoteDraftState
{
    public static string CurrentDraft { get; set; } = string.Empty;
    public static Action? OnDraftRestored { get; set; }
}
```

**2. Wire up your note-taking page:**

```csharp
public partial class NotePage : ContentPage
{
    public NotePage()
    {
        InitializeComponent();

        // Restore any previously saved draft on first load
        DraftEditor.Text = Preferences.Get("draft_text", string.Empty);

        // Keep shared state in sync as user types
        DraftEditor.TextChanged += (s, e) =>
            NoteDraftState.CurrentDraft = e.NewTextValue;

        // Update UI when resumed from background
        NoteDraftState.OnDraftRestored = () =>
            DraftEditor.Text = NoteDraftState.CurrentDraft;
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();
        NoteDraftState.OnDraftRestored = null; // avoid leaks
    }
}
```

**Key points:**

- **`OnStopped`** — fires when the app is fully backgrounded; save here.
- **`OnResumed`** — fires when returning from background; restore here.
- **`OnDestroying`** — also save here because Android's back button can skip `Stopped`.
- Use **`Preferences`** for small values — it's fast enough to avoid ANR/watchdog kills (keep handlers under 1–2 seconds).
- **`Resumed` does not fire on first launch** (`Created → Activated`), so load the initial draft in the page constructor.
